<?php
namespace App\Domain\Hunts;use App\Domain\Hunts\Exceptions\InvalidHuntingZoneException;use App\Domain\Hunts\Exceptions\NoEligibleMonsterException;use App\Domain\Random\RandomNumberGenerator;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Character;use App\Models\Zone;use App\Models\ZoneMonster;use Illuminate\Support\Collection;use InvalidArgumentException;
final class WeightedMonsterSelector{private $rng;public function __construct(RandomNumberGenerator $rng){$this->rng=$rng;}public function eligibleEntries(Zone $zone,Character $character):Collection{if(!$zone->exists||$zone->status!==CatalogStatus::ACTIVE||!$zone->allows_hunting)throw new InvalidHuntingZoneException('Esta zona no permite cacerías.');$level=(int)$character->level;$rows=ZoneMonster::query()->where('zone_id',$zone->id)->where('status',CatalogStatus::ACTIVE)->where('minimum_character_level','<=',$level)->where(function($q)use($level){$q->whereNull('maximum_character_level')->orWhere('maximum_character_level','>=',$level);})->whereHas('monster',function($q){$q->where('status',CatalogStatus::ACTIVE);})->with(['monster'=>function($q){$q->where('status',CatalogStatus::ACTIVE);}])->orderBy('id')->lockForUpdate()->get();if($rows->isEmpty())throw new NoEligibleMonsterException('No existen monstruos disponibles para tu nivel.');return$rows;}public function selectOne(Collection $rows){$total=0;foreach($rows as $row){if(!$row->monster||$row->weight<=0||$row->weight>PHP_INT_MAX-$total)throw new NoEligibleMonsterException('Configuración de pesos inválida.');$total+=(int)$row->weight;}$roll=$this->rng->randomInt(1,$total);$sum=0;foreach($rows as $row){$sum+=(int)$row->weight;if($roll<=$sum)return$row->monster;}throw new NoEligibleMonsterException();}public function selectMany(Collection $rows,$count){if(!is_int($count)||$count<1)throw new InvalidArgumentException('Invalid monster count.');$selected=[];for($i=0;$i<$count;$i++)$selected[]=$this->selectOne($rows);return$selected;}public function select(Zone $zone,Character $character){return$this->selectOne($this->eligibleEntries($zone,$character));}}
